+        const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
+
+        function init() {
+            if (typeof rawData === 'undefined') return;
+            populateFilters();
+            applyFilters();
+            ['filterModule', 'filterMonth', 'filterAgent'].forEach(id => {
+                document.getElementById(id).addEventListener('change', applyFilters);
+            });
+            document.getElementById('tableSearch').addEventListener('input', applyFilters);
+        }
+
+        function populateFilters() {
+            const mods = new Set(), months = new Set(), agents = new Set();
+            rawData.forEach(t => {
+                if(t.Module) mods.add(t.Module);
+                if(t['Agent Name']) agents.add(t['Agent Name']);
+                if(t['Resolved Date']) {
+                    const d = new Date(t['Resolved Date']);
+                    months.add(`${d.getFullYear()}-${(d.getMonth()+1).toString().padStart(2, '0')}`);
+                }
+            });
+
+            const fill = (id, items, label) => {
+                const el = document.getElementById(id);
+                el.innerHTML = `<option value="all">All ${label}</option>`;
+                Array.from(items).sort().forEach(i => {
+                    const opt = document.createElement('option');
+                    opt.value = i;
+                    opt.textContent = id === 'filterMonth' ? `${monthNames[i.split('-')[1]-1]} ${i.split('-')[0]}` : i;
+                    el.appendChild(opt);
+                });
+            };
+            fill('filterModule', mods, 'Modules');
+            fill('filterMonth', months, 'Months');
+            fill('filterAgent', agents, 'Teams');
+        }
+
+        function applyFilters() {
+            const mod = document.getElementById('filterModule').value;
+            const m = document.getElementById('filterMonth').value;
+            const ag = document.getElementById('filterAgent').value;
+            const q = document.getElementById('tableSearch').value.toLowerCase();
+
+            filteredData = rawData.filter(t => {
+                if (mod !== 'all' && t.Module !== mod) return false;
+                if (ag !== 'all' && t['Agent Name'] !== ag) return false;
+                if (m !== 'all') {
+                    const d = new Date(t['Resolved Date']);
+                    if (`${d.getFullYear()}-${(d.getMonth()+1).toString().padStart(2,'0')}` !== m) return false;
+                }
+                if (q) {
+                    const str = `${t.ID} ${t.Subject} ${t['BU Name']}`.toLowerCase();
