+            
+            const cats = {};
+            filteredData.forEach(t=>{ if(t.Category) cats[t.Category] = (cats[t.Category]||0)+1; });
+            const top = Object.entries(cats).sort((a,b)=>b[1]-a[1])[0];
+            document.getElementById('kpiCategory').textContent = top ? top[0] : 'N/A';
