+                borderColor: pastelColors[i % pastelColors.length],
+                backgroundColor: pastelColors[i % pastelColors.length] + '44',
+                fill: true, tension: 0.4, borderWidth: 4, pointRadius: 5, pointBackgroundColor: 'white'
