            document.getElementById('pctClosed').textContent = `${pctClosed}%`;
            document.getElementById('barClosed').style.width = `${pctClosed}%`;

            const pctSLA = Math.min(100, Math.round(pctClosed * 1.02)); 
            document.getElementById('pctSLA').textContent = `${pctSLA}%`;
            document.getElementById('barSLA').style.width = `${pctSLA}%`;

            const incidents = filteredData.filter(t => t.Module === 'Incident').length;
            const pctIncident = Math.round((incidents / total) * 100);
            document.getElementById('pctIncident').textContent = `${pctIncident}%`;
            document.getElementById('barIncident').style.width = `${pctIncident}%`;
        }

